fn solve(n: i64, edges: Vec<Vec<i64>>, label: String) -> i64 {
    let n = n as usize;
    let mut graph: Vec<Vec<usize>> = vec![vec![]; n];
    for edge in &edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        graph[u].push(v);
        graph[v].push(u);
    }

    let mut max_len = 0;
    let label: Vec<char> = label.chars().collect();

    fn dfs(node: usize, visited: &mut Vec<bool>, path: &mut Vec<char>, graph: &Vec<Vec<usize>>, label: &Vec<char>, max_len: &mut i64) {
        if path == path.iter().rev().cloned().collect::<Vec<char>>() {
            *max_len = std::cmp::max(*max_len, path.len() as i64);
        }

        for &neighbor in &graph[node] {
            if !visited[neighbor] {
                visited[neighbor] = true;
                path.push(label[neighbor]);
                dfs(neighbor, visited, path, graph, label, max_len);
                path.pop();
                visited[neighbor] = false;
            }
        }
    }

    for i in 0..n {
        let mut visited = vec![false; n];
        visited[i] = true;
        let mut path = vec![label[i]];
        dfs(i, &mut visited, &mut path, &graph, &label, &mut max_len);
    }

    max_len
}
